mapper.sql:
WITH RECURSIVE period_params AS ( SELECT TO_CHAR(CASE WHEN #{param.billCd} = '30' THEN DATE_TRUNC('month', MAKE_DATE(CAST(#{param.year} AS INTEGER), CAST(#{param.month} AS INTEGER), 1))::date WHEN #{param.billCd} = '20' THEN ((MAKE_DATE(CAST(#{param.year} AS INTEGER), CAST(#{param.month} AS INTEGER), 1) - INTERVAL '1 month') + INTERVAL '20 day')::date END, 'YYYY-MM-DD') AS start_dt, TO_CHAR(CASE WHEN #{param.billCd} = '30' THEN (DATE_TRUNC('month', MAKE_DATE(CAST(#{param.year} AS INTEGER), CAST(#{param.month} AS INTEGER), 1)) + INTERVAL '1 month')::date WHEN #{param.billCd} = '20' THEN (MAKE_DATE(CAST(#{param.year} AS INTEGER), CAST(#{param.month} AS INTEGER), 1) + INTERVAL '20 day')::date END, 'YYYY-MM-DD') AS end_dt ), ultimate_parent_map AS ( SELECT company_id, excclc_company_id AS parent_id, excclc_company_id AS ultimate_id, 1 AS level FROM shipper WHERE del_yn = 'N' AND use_yn = 'Y' UNION ALL SELECT upm.company_id, s.excclc_company_id, s.excclc_company_id, upm.level + 1 FROM ultimate_parent_map upm INNER JOIN shipper s ON upm.ultimate_id = s.company_id WHERE s.del_yn = 'N' AND s.use_yn = 'Y' AND upm.ultimate_id != s.excclc_company_id AND upm.level < 4 ), final_parent_map AS MATERIALIZED ( SELECT fpm.company_id, CAST(fpm.ultimate_id AS INTEGER) AS ultimate_id FROM ( SELECT company_id, ultimate_id, ROW_NUMBER() OVER(PARTITION BY company_id ORDER BY level DESC) AS rn FROM ultimate_parent_map ) fpm INNER JOIN shipper boss_sh ON boss_sh.company_id = fpm.ultimate_id AND boss_sh.bill_company_id = #{param.billCompanyId} AND boss_sh.bill_stdr_cd = #{param.billCd}
AND boss_sh.company_id = #{param.calculationCompanyId}
AND boss_sh.del_yn = 'N' AND boss_sh.use_yn = 'Y' WHERE fpm.rn = 1 ), transport_by_month_all AS ( SELECT tr.transport_id, tr.shipment_operation_date AS tr_shipment_operation_date, tr.sender_company_id, tr.sender_company_nm, tr.sender_transport_shipper_cd, tr.charge_cd, tr.sender_region_cd, tr.sender_region_dtl_cd, tr.sender_manager_nm, tr.sender_address, tr.sender_tel_no, tr.sender_manager_tel_no, tr.sender_rmk, tr.receiver_company_id, tr.receiver_company_nm, tr.receiver_transport_shipper_cd, tr.receiver_region_cd, tr.receiver_region_dtl_cd, tr.receiver_address, tr.receiver_tel_no, tr.receiver_manager_tel_no, tr.receiver_manager_nm, tr.receiver_rmk, tr.del_yn AS tr_del_yn, trd.transport_dtl_id, trd.calculation_cd, trd.calculation_target_cd, trd.sender_receiver_cd, trd.waybill_no, trd.kind_cd, trd.untpc, trd.qty, trd.amount, trd.rmk, trd.shipment_operation_date AS trd_shipment_operation_date, trd.del_yn AS trd_del_yn, fpm.ultimate_id AS boss_id FROM transport_dtl trd INNER JOIN period_params pp ON trd.shipment_operation_date >= pp.start_dt AND trd.shipment_operation_date < pp.end_dt INNER JOIN transport tr ON tr.transport_id = trd.transport_id AND tr.del_yn = 'N' INNER JOIN final_parent_map fpm ON fpm.company_id = ( CASE WHEN trd.calculation_target_cd = 'SENDER' THEN tr.sender_company_id WHEN trd.calculation_target_cd = 'RECEIVER' THEN tr.receiver_company_id END ) WHERE trd.del_yn = 'N' AND trd.calculation_target_cd IN ('SENDER', 'RECEIVER') )
